using System.IO;
using OfficeOpenXml;
using OfficeOpenXml.ExcelPackage;
using OfficeOpenXml.ExcelRange;

class ETG_ItemQualitySpecUploader
{


}

Method.Source:
/// <summary>
/// Runs the class with the specified arguments.
/// </summary>
/// <param name = "_args">The specified arguments.</param>
public static void main(Args _args)
{
    System.IO.Stream		    stream;
    ExcelSpreadsheetName	    sheeet;
    FileUploadBuild			    fileUpload;
    DialogGroup				    dlgUploadGroup;
    FileUploadBuild			    fileUploadBuild;
    FormBuildControl		    formBuildControl;
    int                          counter,minrange,maxrange;
    InventTable				     inventTable;       
    ETG_ItemQualityGrp           itemQualitygrp;
    ETG_ItemQualitySpecDetails   itemQualitySpecDetails;
    ItemId					     itemID;
    ETGQUALITYSPECIFICATIONGROUP qualityspecgrp;
    Name                         groupid,maxrangeUpd,minrangeUpd;
    CalculationType              calculationType;

    Dialog dialog = new Dialog("Import Item Quality Specifications");

    dlgUploadGroup		= dialog.addGroup("Select Excel File to Upload.");
    formBuildControl	= dialog.formBuildDesign().control(dlgUploadGroup.name());
    fileUploadBuild		= formBuildControl.addControlEx(classstr(FileUpload), 'Upload');

    fileUploadBuild.style(FileUploadStyle::MinimalWithFilename);
    fileUploadBuild.fileTypesAccepted('.xlsx');


    if (dialog.run() && dialog.closedOk())
    {
        FileUpload fileUploadControl					  = dialog.formRun().control(dialog.formRun().controlId('Upload'));
        FileUploadTemporaryStorageResult fileUploadResult = fileUploadControl.getFileUploadResult();

        if (fileUploadResult != null && fileUploadResult.getUploadStatus())
        {
            stream = fileUploadResult.openResult();
            using (ExcelPackage Package = new ExcelPackage(stream))
            {
                int rowCount, i;

                Package.Load(stream);
                ExcelWorksheet worksheet		= package.get_Workbook().get_Worksheets().get_Item(1);
                OfficeOpenXml.ExcelRange range	= worksheet.Cells;
                rowCount = worksheet.Dimension.End.Row - worksheet.Dimension.Start.Row + 1;

                for (i = 2; i<= rowCount; i++)
                {

                    itemID                   = range.get_Item(i, 1).Value;
                    groupid                  = range.get_Item(i, 2).Value;
                    minrange                 = str2Int(range.get_Item(i,6).Value);
                    maxrange                 = str2Int(range.get_Item(i,7).Value);
                    qualityspecgrp  = ETGQUALITYSPECIFICATIONGROUP::find(groupid);

                    select firstonly inventTable
                        where inventTable.ItemId == itemID;

                    if(minrange > maxrange)
                    {
                        error(strFmt('Max range should be greater than min range for Groupid in Item %1 %2', groupid, itemID));
                    }

                    if(maxrange > minrange)
                    {
                        maxrangeUpd = 'Maximum value';
                    }

                    if(minrange > maxrange)
                    {
                        minrangeUpd = 'Minumun value';
                    }

                    if(inventTable && maxrangeUpd && groupid)
                    {
                        itemQualitygrp.clear();
                        itemQualitySpecDetails.clear();

                        try
                        { 

                            itemQualitygrp.GroupId                        = range.get_Item(i, 2).Value;
                            itemQualitygrp.ItemId                         = inventTable.ItemId;
                            itemQualitySpecDetails.GroupID                = range.get_Item(i, 2).Value;
                            itemQualitySpecDetails.ItemId                 = inventTable.ItemId;
                            itemQualitySpecDetails.GroupDescription       = qualityspecgrp.GroupDescription;
                            itemQualitySpecDetails.SubGrpId               = range.get_Item(i,2).Value;
                            itemQualitySpecDetails.SubGroupId             = range.get_Item(i,2).Value;
                            itemQualitySpecDetails.SubGroupDescription    = qualityspecgrp.GroupDescription;
                            itemQualitySpecDetails.MeasurementType        = str2Enum(calculationType,range.get_Item(i,3).Value);
                            itemQualitySpecDetails.Increment              = str2Int(range.get_Item(i,4).Value);
                            itemQualitySpecDetails.FixedValue             = str2Int(range.get_Item(i,5).Value);
                            itemQualitySpecDetails.MinRange               = str2Int(range.get_Item(i,6).Value);
                            itemQualitySpecDetails.MaxRange               = str2Int(range.get_Item(i,7).Value);


                            maxrangeUpd = '';
                            minrangeUpd = '';

                            ttsbegin;
                            if(itemQualitygrp.validateWrite())
                            {
                                itemQualitygrp.insert();
                                itemQualitySpecDetails.insert();
                            }

                            ttscommit;
                            counter++;

                        }
                        catch(Exception::Error)
                        {
                            ttsabort;
                        }
                    }

                }
                info(strFmt('Item Quality Specifications Uploaded Sucessfully. Total Lines %1 : ',counter));
            }
        }
        else
        {
            error("Error During Upload. Please Contact System Admin. Item ID %1",itemID);
        }

    }
}
